import{_ as e,o as t,c as a,V as o}from"./chunks/framework.509d3f30.js";const g=JSON.parse('{"title":"Uploading fraud data","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials-web/uploading-fraud-data.md","filePath":"tutorials-web/uploading-fraud-data.md"}'),r={name:"tutorials-web/uploading-fraud-data.md"},n=o('<h1 id="uploading-fraud-data" tabindex="-1">Uploading fraud data <a class="header-anchor" href="#uploading-fraud-data" aria-label="Permalink to &quot;Uploading fraud data&quot;">​</a></h1><p>To upload fraud event data via FIB Web UI, perform the following steps:</p><ol><li><p>From the top right menu, select <strong>Upload</strong>.</p></li><li><p>On the <strong>Upload Fraud Data</strong> screen that appears, specify the following data:</p><ul><li><strong>Select Fraud Type</strong> dropdown menu — select the fraud type of the fraud event that you are uploading.</li><li><strong>Select Transaction Type</strong> dropdown menu — select <strong>Add Fraud Data</strong>.</li><li><strong>Data Upload</strong> box — input the following data about the fraud event, separated by comma: <ul><li>The <code>id</code> fraud identifier.</li><li>The two-digit code of the country the fraud event originated from (Alpha-2, ISO 3166).</li><li>The two-digit code of the country the fraud event was identified as such (Alpha-2, ISO 3166).</li></ul></li></ul><blockquote><p><strong>Example</strong>: +33000123456, FR, ZA</p></blockquote><div class="tip custom-block"><p class="custom-block-title">Note</p><p>If you are uploading a range of fraud identifiers (i.e., a range of phone numbers or IP addresses), select <strong>This is a Fraud data range</strong>.</p><p>In this case, the following data about the fraud event is input, separated by comma: The starting and ending values for the range of fraud identifiers, the origination country two-digit code, and the destination country two-digit code.</p><p><strong>Example</strong>: +447000123456, +447000123460, GB, US</p></div></li><li><p>Select <strong>Upload to Ledger</strong> to upload the fraud event data.</p></li></ol><p>For more information on fraud event data, including fraud identifiers, fraud types, and other relevant concepts, see <a href="./../overview/fraud-events.html">Fraud Events</a>.</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>If you are uploading several individual fraud identifiers, each entry must start from a new line.</p><p>A single fraud event data submission can contain up to 500 entries.</p></div><h3 id="expected-result" tabindex="-1">Expected result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected result&quot;">​</a></h3><p>Your list of contributions is updated and the credit balance is increased based on the current conversion rate active in the network (see <a href="./../overview/tokenomics.html#current-conversion-rate">Current conversion rate</a>).</p>',7),i=[n];function d(s,l,u,p,c,f){return t(),a("div",null,i)}const m=e(r,[["render",d]]);export{g as __pageData,m as default};
